const coupons = {
  "COUPON1": {
    code: "COUPON1",
    discount: 0.1,
    expirationDate: new Date("2023-04-15"),
    used: false
  },
  "COUPON2": {
    code: "COUPON2",
    discount: 0.2,
    expirationDate: new Date("2023-04-15"),
    used: false
  }
};

function redeemCoupon(couponCode) {
  const coupon = coupons[couponCode];
  if (!coupon || !coupon.used && isValidDate(coupon.expirationDate)) {
    throw new Error("Invalid coupon code or expired");
  }
  coupon.used = true;
  return applyDiscount(coupon.discount);
}

function isValidDate(date) {
  const now = new Date();
  return date > now;
}

function applyDiscount(discount) {
  // Apply the discount to the current order
  return {
    total: 100 - (100 * discount),
    discount: discount
  };
}